/*【▪中式恐怖|冥契▪】作者：易碎蝶*/
/*🍃←这个是可以调整的部分，以及用了【这个符号】*/

/* ====== 全局字体设置 ====== */
@import url("https://fontsapi.zeoseven.com/309/main/result.css");

body {
    font-family: "KingHwa_OldSong";
    font-weight: normal;
}
/*———————— 移动端顶栏背景 ————————*/
#top-bar {
    position: fixed !important;  /* 改为固定定位适配移动端 */
    overflow: visible !important;
    background: none !important;
    border: 0 !important;
    box-shadow: none !important;
    pointer-events: none;
    width: 100vw;  /* 全屏宽度 */
    height: 106px;  /* 适合移动端的顶部高度 */
    top: 0;
    left: 0;
}

#top-bar::before {
    content: "";
    position: fixed;
    background: url("https://i.postimg.cc/RF1q7kBv/Image-245170514363690.png") no-repeat center / cover;  /* 使用cover适配屏幕 */

    /* 移动端适配定位 */
    top: 0px;
    left: 0px;
    right: 2px;
    bottom: 70px;

    /* 层级控制 */
    z-index: 3004;
    pointer-events: auto;

    /* 移除动画相关属性 */
    transform: none !important;
    animation: none !important;
}

/* —————面板背景图———— */
.drawer-content {
  background-image: url('https://i.postimg.cc/D0x2wFqY/Image-240547867825337.png'); /* 示例图片URL */
  background-size: cover; /* 图片覆盖整个元素 */
  background-position: center; /* 图片居中显示 */
  background-repeat: no-repeat; /* 图片不重复 */
  background-attachment: fixed; /* 固定背景图片 */
}

/*——————滑块——————*/
input[type="range"]::-webkit-slider-thumb {
  -webkit-appearance: none;
  appearance: none;
  width: 45px;
  height: 45px;
  background: transparent url('https://i.postimg.cc/50W6FxDP/Image-245174853620921.png') center/cover no-repeat;
  border: none;
  border-radius: 0;
  box-shadow: none;
  cursor: ew-resize;
  position: relative;
  z-index: 1;
}

/*——————装饰层——————*/
/* /* ==============================================
 * 1. 🍃装饰层模块
 * ==============================================*/
/* 🍃上层装饰层 - 位于气泡上方 */
.mes::before {
  content: "";
  position: absolute;
  top: -138px; /* 上层装饰层【上下】(负值表示向上) */
  left: -15px; /* 上层装饰层【左右】 */
  width: 380px; /* 调整上层装饰层的【宽度/大小】 */
  height: 437px; /* 调整上层装饰层的【高度/大小】 */
  background-image: url('https://i.postimg.cc/kXj4nNsX/Image-240553675163722.png'); /* 替换为你的图片链接 - 上层装饰层图片 */
  background-size: contain; /* 图片适应容器尺寸 */
  background-repeat: no-repeat; /* 不重复显示图片 */
  z-index: 40; /* 确保在气泡上方 */
  pointer-events: none; /* 避免阻挡鼠标事件 */
}



/* 🍃下层装饰层 - 位于气泡下方，跟随气泡尾部移动 */
.mes::after {
  content: "";
  position: absolute;
  bottom: -410px; /* 下层装饰层【上下】(负值表示向下) */
  right: -23px; /* 下层装饰层【左右】 */
  width: 400px; /* 调整下层装饰层的【宽度/大小】 */
  height: 470px; /* 调整下层装饰层的【高度/大小】 */
  background-image: url('https://i.postimg.cc/SNNDHqjY/Image-244339576120871.png'); /* 替换为你的图片链接 - 下层装饰层图片 */
  background-size: contain; /* 图片适应容器尺寸 */
  background-repeat: no-repeat; /* 不重复显示图片 */
  z-index: 42; /* 确保在气泡上方 */
  pointer-events: none; /* 避免阻挡鼠标事件 */
}

/*——————🍃文本边距调整——————*/
/* 消息文本容器（可独立调整上下左右边距） */
.mes_text, 
.mes_reasoning {
    /* 基础样式 */
    font-weight: 500;
    line-height: calc(var(--mainFontSize) + .5rem);
    text-align: left; /* 文本左对齐 */
    overflow-wrap: anywhere;

    /* 🍃可独立调整的边距系统 */
    --top-padding: 2rem; /* 气泡顶部留白 */
    --bottom-padding: 3rem; /* 气泡底部留白 */
    --left-padding: 0.4rem; /* 气泡左边距 */
    --right-padding: 0.70rem; /* 气泡右边距 */

    padding-top: var(--top-padding);
    padding-bottom: var(--bottom-padding);
    padding-left: var(--left-padding);
    padding-right: var(--right-padding);

    /* 最大宽度控制 */
    max-width: 700%;
    margin: 0; /* 清除默认外边距 */

    /* 气泡视觉相关样式（可根据UI需求扩展） */
    /* background-color: #f0f0f0; */
    /* border-radius: 19px; */
}



/*——————最新消息箭头图标替换——————*/


/*——————气泡设置——————*/

/* ==============================================
 * 1.🍃 气泡容器模块
 * ==============================================*/
.mes {
  max-width: 350px;/*【🍃宽度】*/
  width: 400%;/*【🍃宽度，一般调整第一个就行，没效果再调整这个】*/
  margin: 120px auto 190px;/*【AI和用户的气泡距离】*/
  border-radius: 0px;
  /* 移除渐变背景和阴影 */
  background: url('https://i.postimg.cc/sDfxdHpN/Image-240550637276414.png') repeat-y; /* 添加重复方向 */
  background-size: 100% auto; /* 保持宽度适配 */
  background-attachment: local; /* 确保滚动时背景同步 */
  transition: transform 0.2s ease; /* 移除阴影过渡 */
  transform-origin: top center;
  position: relative;
  overflow: visible;
  box-shadow: none !important; /* 强制移除所有阴影 */
}



/* ==============================================
 * 2. 🍃头像容器模块
 * ============================================== */
.mesAvatarWrapper {
  position: absolute;
  top: -118px;           /* 【控制头像在气泡上方的位置】 */
  left: 50%;            /* 【调整头像左右】 */
  transform: translateX(-50%);
  z-index: 1;
}

/* ==============================================
 * 3. 头像图像模块（可自定义形状）
 * ============================================== */
.mesAvatarWrapper .avatar {
  /* 🍃基础尺寸 - 可自定义修改 */
  width: 145px;           /* 头像宽度 */
  height: 140px;          /* 头像高度 */

  /* 形状控制 - 默认圆形 */
  border-radius: 50%;    /* 圆形（50%），可修改为不同值创建椭圆或圆角矩形 */

  /* 外观样式 */
  overflow: hidden;
  border: 3px solid #fff;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.15);
  transition: all 0.3s ease;

  /* 新增旋转效果（固定角度） */
  transform: rotate(-0deg); /* 顺时针旋转15度 */
}

.mesAvatarWrapper .avatar img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

/* ==============================================
 * 4. 楼层显示
 * ============================================== */
.mes .mesIDDisplay {
    position: fixed;  /* 使用固定定位 */
    top: 230;           /* 固定在顶部 */
    left: -46%;        /* 【楼层左右】 */
    transform: translateX(-50%); /* 精确居中 */
    z-index: 999;    /* 确保在最顶层 */
    margin-top: 73px; /* 【楼层上下】 */

    /* 简约样式 */
    padding: 2px 12px;
    background: rgba(255, 255, 255, 0.0); /* 【这里可以填楼层显示的背景色，最后一个数字区调整透明度】 */
    border-radius: 4px;
    box-shadow: 90 2px px rgba(0, 0, 0, 0.1);

    /* 保留原有样式 */
    cursor: default;
    opacity: 0.7;
    font-size: calc(var(--mainFontSize) * 0.9);
    font-weight: 600;
    color: #CECECE; /* 【调整楼层显示的颜色】 */
}

/* 其他元素保持原有样式 */
.mes .mes_timer, .mes .tokenCounterDisplay {
    cursor: default;
    opacity: 0.7;
    font-size: calc(var(--mainFontSize) * 0.9);
    font-weight: 600;
    text-align: center;
}
/* ==============================================
 * 5. 🍃基础信息位置调整【时间戳等】
 * ============================================== */
.mes_block {
  position: relative; /* 保留定位基准 */
}

/* 关键：用伪元素作为占位符，占据 .ch_name 的空间 */
.mes_block::before {
  content: ""; /* 必须属性 */
  display: block; /* 块级元素，占据空间 */
  height: 100px; /* 【上下/留白】 */
  /* 若 .ch_name 高度由内容决定，可改为 min-height 或通过 JS 动态获取 */
}

.mes_block .ch_name {
  max-width: calc(100% - 105px); /* 原 left:95px + right:10px = 145px 留白 */
  min-height: 50px;
  position: absolute; /* 保持绝对定位，自由控制位置 */
  top: 0.5; /* 顶部紧贴 */
  left: 18px; /*【 左侧偏移】 */
  right: 55px; /* 【右侧留白】 */
  /* 移除 bottom，避免强制撑开高度 */
}
}

/* ==============================================
 * 🕒 计时器 & 🔤 字符计数显示组件
 * 可自由调整位置和颜色，避免被遮挡
 * ============================================== */

.mes {
  position: relative; /* 创建定位上下文 */
}

/* 通用样式 */
.mes .mes_timer,
.mes .tokenCounterDisplay {
  position: fixed; /* 使用固定定位确保不被遮挡 */
  z-index: 2147483647; /* 最高层级 (32位整数最大值) */
  cursor: default;
  opacity: 0.85;
  font-size: calc(var(--mainFontSize) * 0.9);
  font-weight: 600;
  text-align: center;
  padding: 4px 12px;
  border-radius: 12px;
  background: rgba(30, 30, 30, 0.0); /* 半透明白色背景 */
  backdrop-filter: blur(0px); /* 毛玻璃效果 */
  box-shadow: 0 2px 8px rgba(0,0,0,0.15);

  /* 默认位置 - 顶部居中 */
  top: 240px;
  left: 50%;
  transform: translateX(-50%);

  /* 颜色变量 - 便于单独修改 */
  --timer-color: #CECECE;
  --counter-color: #CECECE;
}

/* 单独控制计时器 */
.mes .mes_timer {
  /* 位置调整 */
  top: var(--timer-top, 210px);  /* 【计时器上下】 */
  left: var(--timer-left, 20%);/*【计时器左右】*/
  transform: translateX(var(--timer-translate, -50%));

  /* 颜色控制 */
  color: var(--timer-color, #CECECE);
}

/* 单独控制字符计数 */
.mes .tokenCounterDisplay {
  /* 位置调整 */
  top: var(--counter-top, 210px); /* 【字符上下】 */
  left: var(--counter-left, -32%);/* 【字符左右】 */
  transform: translateX(var(--counter-translate, -0%));

  /* 颜色控制 */
  color: var(--counter-color, #CECECE);
}
}

