/*——————复选——————*/
body {
  background: #1d0000; /* 暗红背景 */
}

input[type='checkbox'] {
  appearance: none;
  width: 20px;
  height: 20px;
  border: 2px solid #AEE9DE; /* 冥界蓝绿边框 */
  border-radius: 5px;
  cursor: pointer;
  position: relative;
  background: #000000; /* 纯黑背景 */
  transition: all 0.3s cubic-bezier(0.68, -0.55, 0.27, 1.55);
  box-shadow: 
    inset 2px 2px 4px rgba(120,0,0,0.6), /* 血红内阴影 */
    0 4px 6px rgba(90,0,0,0.7); /* 深红投影 */
}

input[type='checkbox']:hover {
  transform: scale(1.1);
  box-shadow: 
    inset 2px 2px 5px rgba(160,0,0,0.7),
    0 5px 8px rgba(120,0,0,0.8);
  border-color: #ff0000; /* 悬停时血红色边框 */
}

input[type='checkbox']:checked {
  background: #2a0000; /* 暗红选中背景 */
  border-color: #ff0000; /* 血红色边框 */
  animation: jelly 0.6s ease;
  box-shadow: 
    inset 2px 2px 5px rgba(160,0,0,0.7),
    0 4px 8px rgba(120,0,0,0.8);
}

input[type='checkbox']:checked::after {
  content: '◈'; /* 符咒标记 */
  position: absolute;
  top: 52%;
  left: 49%;
  transform: translate(-50%, -55%) rotate(0deg);
  color: #ff0000; /* 血红色标记 */
  font-size: 20px;
  font-weight: bold;
  text-shadow: 0 0 5px rgba(255,0,0,0.9); /* 红光晕染 */
}
/*——————大效果美化——————*/
background: #0a0000 !important;
  box-shadow: 
    0 0 0 2px #9a0000, 
    4px 4px 4px rgba(0,0,0,0.8),
    inset 0 0 12px rgba(154, 0, 0, 0.3);
}

small, i, em {
  color: #AEE9DE !important;
  text-shadow: 0 1px 3px rgba(0, 0, 0, 0.7);
  font-style: italic;
}

code {
  background: #0a0000;
  color: #AEE9DE;
  border: 0.5px solid #7a0000;
  box-shadow: 
    3px 3px 4px rgba(0,0,0,0.0),
    inset 3px -2px 0px rgba(154, 0, 0, 0.4);
}
code::before {
  content: "▪";
  color: #9a0000;
}

.mes_text q {
