.drawer-content select {
  width: 100%;
  padding: 8px px 14px 20px;
  appearance: none;
  -webkit-appearance: none;
  -moz-appearance: none;
  cursor: pointer;

  /* 冥契阴间色调 */
  background-color: rgba(30, 0, 0, 0.6);
  border: 2px solid #8B0000;
  border-radius: 4px;

  /* 冥间风格阴影 */
  box-shadow: 
    inset 0 0 12px rgba(0, 0, 0, 0.7),
    9px 8px 0 rgba(90, 0, 0, 0.3);

  background-image: url("https://i.postimg.cc/RF1q7kBv/Image-245170514363690.png");
  background-repeat: no-repeat;
  background-position: right -0px center;
  background-size: 450px;

  /* 冥契文字样式 */
  font-family: 'Quicksand', sans-serif;
  font-size: 12px;
  color: #AEE9DE;
  letter-spacing: 0.5px;

  transition: all 0.1s cubic-bezier(0.175, 0.25, 0.32, 0.275);
  transform-origin: center;
}

.drawer-content select:hover {
  transform: scale(1.02);
  border-color: #AEE9DE;
  background-color: rgba(50, 0, 0, 0.98);

  box-shadow: 
    inset 0 0 15px rgba(0, 0, 0, 0.9),
    8px 8px 0 rgba(139, 0, 0, 0.5);
}

.drawer-content select:focus {
  outline: none;
  border-color: #AEE9DE;
  background-color: rgba(60, 0, 0, 1);

  box-shadow: 
    inset 0 0 18px rgba(0, 0, 0, 1),
    0 0 0 3px rgba(174, 233, 222, 0.35),
    10px 10px 0 rgba(139, 0, 0, 0.6);

  animation: jellyFocus 0.9s ease;
}

.drawer-content select option {
  background: rgba(20, 0, 0, 0.98);
  color: #AEE9DE;
  padding: 2px 20px;
  margin: 4px 0;
  border-radius: 12px;
  transition: all 0.3s ease;
}

.drawer-content select option:hover {
  background: rgba(139, 0, 0, 0.35) !important;
  transform: translateX(8px);
  box-shadow: 2px 2px 6px rgba(0, 0, 0, 0.4);
}

@keyframes jellyFocus {
  0% { transform: scale(5); }
  10% { transform: scale(1.05); }
  20% { transform: scale(0.98); }
  30% { transform: scale(1); }
}
/*——————框美化五——————*/
/* 黑白日漫风格-夜间模式 */
input:not([type="file" i], [type="image" i], [type="checkbox" i], [type="radio" i]) {
  background: #110000;
  border: 1px solid #700000;
  border-radius: 0rem;
  padding: 0.1rem 0.8rem;
  transition: all 0.25s ease;
  color: #AEE9DE;
  font-size: 0.6rem;
  height: 1.5rem;
  box-shadow: 
    3px 3px 0 rgba(90, 0, 0, 0.7),
    inset 0 0 9px rgba(120, 0, 0, 0.8);
}

/* 聚焦状态-白色高光 */
input:not([type="file" i], [type="image" i], [type="checkbox" i], [type="radio" i]):focus {
  outline: none;
  border-color: #AEE9DE;
  transform: translateY(-0px);
  box-shadow: 
    3px 3px 0 rgba(70, 0, 0, 0.8),
    inset 0 0 10px rgba(100, 0, 0, 0.9);
}

/* 悬停状态-浅灰效果 */
input:not([type="file" i], [type="image" i], [type="checkbox" i], [type="radio" i]):hover {
  background: #1a0000;
  border-color: #A00000;
}

/* 禁用状态-深灰效果 */
input:not([type="file" i], [type="image" i], [type="checkbox" i], [type="radio" i]):disabled {
  background: #000;
  border-color: #400000;
  color: #5a8a7e;
  cursor: not-allowed;
}
